'use client';

import { useState, useEffect } from 'react';
import { Certificado, Curso } from '@/types/certificate';

interface Props { cert: Certificado; onClose: () => void; }

const FRENTE_JPG = 'data:image/jpeg;base64,';
const TRAS_JPG   = 'data:image/jpeg;base64,';

export default function CertificadoPreview({ cert, onClose }: Props) {
  const [exporting, setExporting] = useState(false);
  const [curso, setCurso]         = useState<Curso | null>(null);
  const [view, setView]           = useState<'frente' | 'verso'>('frente');

  const formatDate = (d: string) =>
    new Date(d).toLocaleDateString('pt-PT', { day: '2-digit', month: 'long', year: 'numeric' });

  useEffect(() => {
    fetch('/api/cursos')
      .then(r => r.json())
      .then((cursos: Curso[]) => {
        const match = cursos.find(c =>
          c.nome.toLowerCase() === cert.curso.toLowerCase() || c.id === cert.cursoId
        );
        if (match) setCurso(match);
      })
      .catch(() => {});
  }, [cert.curso, cert.cursoId]);

  const exportPDF = async () => {
    setExporting(true);
    try {
      const { jsPDF } = await import('jspdf');
      const pdf = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
      const W = pdf.internal.pageSize.getWidth();   // 297mm
      const H = pdf.internal.pageSize.getHeight();  // 210mm

      // ── PÁGINA 1: FRENTE ──────────────────────────────────────
      pdf.addImage(FRENTE_JPG, 'JPEG', 0, 0, W, H);

      // Curso — ~36% do topo
      pdf.setFont('helvetica', 'bold');
      pdf.setFontSize(13);
      pdf.setTextColor(20, 20, 20);
      const cursoLines = pdf.splitTextToSize(cert.curso.toUpperCase(), W - 80);
      pdf.text(cursoLines, W / 2, H * 0.39, { align: 'center' });

      // Nome do formando — ~51% do topo
      pdf.setFont('times', 'italic');
      pdf.setFontSize(22);
      pdf.setTextColor(20, 20, 20);
      pdf.text(cert.nomeFormando, W / 2, H * 0.51, { align: 'center' });

      // Data de emissão — 75% do topo
      pdf.setFont('helvetica', 'normal');
      pdf.setFontSize(10);
      pdf.setTextColor(20, 20, 20);
      pdf.text(`Luanda, ${formatDate(cert.dataEmissao)}`, W / 2, H * 0.75, { align: 'center' });

      // QR Code — canto inferior esquerdo
      if (cert.qrCodeUrl) {
        const qrSize = W * 0.09;
        const qrX = W * 0.11;
        const qrY = H * 0.78;
        pdf.addImage(cert.qrCodeUrl, 'PNG', qrX, qrY, qrSize, qrSize);
        pdf.setFont('courier', 'normal');
        pdf.setFontSize(5);
        pdf.setTextColor(60, 60, 60);
        pdf.text(cert.numeroCertificado || '', qrX + qrSize / 2, qrY + qrSize + 3, { align: 'center' });
      }

      // ── PÁGINA 2: VERSO ───────────────────────────────────────
      if (curso?.conteudoProgramatico) {
        pdf.addPage();
        pdf.addImage(TRAS_JPG, 'JPEG', 0, 0, W, H);

        const lines     = curso.conteudoProgramatico.split('\n');
        const mid       = Math.ceil(lines.length / 2);
        const col1Lines = lines.slice(0, mid);
        const col2Lines = lines.slice(mid);

        const colW  = (W - 40) / 2;
        const col1X = 14;
        const col2X = W / 2 + 6;
        let yPos    = H * 0.20;

        const renderColumn = (colLines: string[], startX: number) => {
          let y = yPos;
          for (const line of colLines) {
            const trimmed = line.trim();
            if (!trimmed) { y += 3; continue; }
            const isMod = trimmed.startsWith('Módulo') || trimmed.startsWith('MÓDULO') || trimmed.startsWith('Modulo');

            if (isMod) {
              y += 6;
              pdf.setFont('helvetica', 'bold');
              pdf.setFontSize(9);
              pdf.setTextColor(20, 20, 20);
              const wrapped = pdf.splitTextToSize(trimmed, colW - 2);
              wrapped.forEach((wline: string) => {
                pdf.text(wline, startX + colW / 2, y, { align: 'center' });
                y += 5.5;
              });
              y += 1;
            } else {
              pdf.setFont('helvetica', 'normal');
              pdf.setFontSize(8);
              pdf.setTextColor(40, 40, 40);
              const cleanLine = trimmed.startsWith('•') ? trimmed.substring(1).trim() : trimmed;
              const wrapped = pdf.splitTextToSize(cleanLine, colW - 4);
              wrapped.forEach((wline: string) => {
                pdf.text(wline, startX + colW / 2, y, { align: 'center' });
                y += 4.5;
              });
              y += 0.5;
            }
            if (y > H - 20) break;
          }
        };

        renderColumn(col1Lines, col1X);
        renderColumn(col2Lines, col2X);
      }

      pdf.save(`Certificado_${cert.numeroCertificado}_${cert.nomeFormando.replace(/\s+/g, '_')}.pdf`);
    } catch (err) {
      console.error('Erro PDF:', err);
      alert('Erro ao gerar PDF: ' + (err instanceof Error ? err.message : String(err)));
    } finally { setExporting(false); }
  };

  // Preview verso — dividir em 2 colunas
  const splitColumns = (text: string) => {
    const lines = text.split('\n').filter(l => l.trim());
    const mid = Math.ceil(lines.length / 2);
    return [lines.slice(0, mid), lines.slice(mid)];
  };
  const [col1, col2] = splitColumns(curso?.conteudoProgramatico || '');

  const renderLine = (line: string, i: number) => {
    const t      = line.trim();
    const isMod  = t.startsWith('Módulo') || t.startsWith('MÓDULO') || t.startsWith('Modulo');
    const isBullet = t.startsWith('•');
    return (
      <p key={i} style={{
        margin: isMod ? '8px 0 3px' : '1px 0',
        fontSize: isMod ? 'clamp(7px,0.85vw,10px)' : 'clamp(6px,0.75vw,9px)',
        fontWeight: isMod ? 700 : 400,
        color: isMod ? '#1a1a1a' : '#333',
        textAlign: 'center',
        lineHeight: 1.5,
        fontFamily: isMod ? 'Georgia, serif' : 'Arial, sans-serif',
      }}>{isBullet ? t.substring(1).trim() : t}</p>
    );
  };

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-sm z-50 flex items-start justify-center p-4 overflow-y-auto" onClick={onClose}>
      <div className="w-full max-w-5xl my-6" onClick={e => e.stopPropagation()}>

        {/* Toolbar */}
        <div className="flex items-center justify-between mb-4">
          <button onClick={onClose} className="text-slate-400 hover:text-white text-sm transition">← Fechar</button>
          <div className="flex items-center gap-3">
            <div className="flex gap-1 bg-slate-800 rounded-lg p-1">
              {(['frente', 'verso'] as const).map(v => (
                <button key={v} onClick={() => setView(v)}
                  className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${view === v ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>
                  {v === 'frente' ? '🎓 Frente' : '📋 Verso'}
                </button>
              ))}
            </div>
            <a href={`/verificar/${cert.id}`} target="_blank" rel="noopener noreferrer"
              className="px-4 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-lg text-sm transition">🔗 Verificar</a>
            <button onClick={exportPDF} disabled={exporting}
              className="px-4 py-2 bg-blue-600 hover:bg-blue-500 disabled:opacity-60 text-white rounded-lg text-sm font-bold transition flex items-center gap-2">
              {exporting
                ? <><span className="w-3.5 h-3.5 border-2 border-white/30 border-t-white rounded-full animate-spin"/>A gerar PDF...</>
                : `⬇ PDF${curso?.conteudoProgramatico ? ' (2 págs)' : ''}`}
            </button>
          </div>
        </div>

        {/* FRENTE */}
        {view === 'frente' && (
          <div style={{
            position: 'relative', width: '100%', aspectRatio: '1625 / 1125',
            backgroundImage: `url(${FRENTE_JPG})`,
            backgroundSize: '100% 100%', overflow: 'hidden',
            boxShadow: '0 25px 70px rgba(0,0,0,0.5)',
          }}>
            {/* Curso */}
            <div style={{ position: 'absolute', top: '39%', left: '10%', right: '10%', textAlign: 'center' }}>
              <p style={{ margin: 0, color: '#141414', fontSize: 'clamp(10px,1.6vw,20px)', fontWeight: 700, letterSpacing: '0.05em', textTransform: 'uppercase', fontFamily: 'Arial, sans-serif', lineHeight: 1.3 }}>
                {cert.curso.toUpperCase()}
              </p>
            </div>
            {/* Nome */}
            <div style={{ position: 'absolute', top: '51%', left: '10%', right: '10%', textAlign: 'center' }}>
              <p style={{ margin: 0, color: '#141414', fontSize: 'clamp(16px,2.8vw,36px)', fontFamily: "'Times New Roman', Georgia, serif", fontStyle: 'italic', lineHeight: 1.2 }}>
                {cert.nomeFormando}
              </p>
            </div>
            {/* Data de emissão */}
            <div style={{ position: 'absolute', top: '75%', left: '10%', right: '10%', textAlign: 'center' }}>
              <p style={{ margin: 0, color: '#141414', fontSize: 'clamp(8px,1.1vw,13px)', fontFamily: 'Arial, sans-serif' }}>
                Luanda, {formatDate(cert.dataEmissao)}
              </p>
            </div>
            {/* QR Code */}
            <div style={{ position: 'absolute', top: '78%', left: '11%', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2 }}>
              {cert.qrCodeUrl && <img src={cert.qrCodeUrl} alt="QR" style={{ width: 'clamp(45px,7vw,75px)', height: 'clamp(45px,7vw,75px)' }} />}
              <p style={{ margin: 0, color: '#444', fontSize: 'clamp(4px,0.55vw,6px)', fontFamily: 'monospace', textAlign: 'center' }}>{cert.numeroCertificado}</p>
            </div>
          </div>
        )}

        {/* VERSO */}
        {view === 'verso' && (
          <div style={{
            position: 'relative', width: '100%', aspectRatio: '1625 / 1125',
            backgroundImage: `url(${TRAS_JPG})`,
            backgroundSize: '100% 100%', overflow: 'hidden',
            boxShadow: '0 25px 70px rgba(0,0,0,0.5)',
          }}>
            <div style={{ position: 'absolute', top: '20%', left: '5%', right: '5%', bottom: '8%', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 4%' }}>
              <div style={{ overflow: 'hidden' }}>{col1.map((l, i) => renderLine(l, i))}</div>
              <div style={{ overflow: 'hidden' }}>{col2.map((l, i) => renderLine(l, i + col1.length))}</div>
            </div>
            {!curso?.conteudoProgramatico && (
              <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                <p style={{ color: '#999', fontSize: 14 }}>Sem conteúdo programático definido.</p>
              </div>
            )}
          </div>
        )}

        <div className="mt-3 flex items-center justify-between text-xs text-slate-600 px-1">
          <span>Nº {cert.numeroCertificado}</span>
          <span>{formatDate(cert.dataEmissao)}</span>
          <span>ID: {(cert.id as string)?.substring(0, 8)}...</span>
        </div>
      </div>
    </div>
  );
}
